package postage

import (
	"context"
	"sync"
	"time"

	"github.com/ethersphere/bee/v2/pkg/storage"
)

var _ storage.Store = (*StamperStoreCache)(nil)

// StamperStoreCache wraps a storage.Store to memory-buffer Put operations.
// It is explicitly designed to intercept high-frequency StampItem writes
// generated by stamper.go during mass chunk uploads, compressing thousands
// of sequential disk writes into sporadic batched flushes.
type StamperStoreCache struct {
	storage.Store

	cache sync.Map // map[string][]byte

	quit chan struct{}
	wg   sync.WaitGroup
}

// key returns a strictly unique string for the storage Item
func key(i storage.Key) string {
	return i.Namespace() + "/" + i.ID()
}

// NewStamperStoreCache instantiates a write-delayed cache over the given store.
// Flush operations run in the background every 5 seconds.
func NewStamperStoreCache(store storage.Store) *StamperStoreCache {
	c := &StamperStoreCache{
		Store: store,
		quit:  make(chan struct{}),
	}

	c.wg.Add(1)
	go c.flushLoop()

	return c
}

// Get intercepts storage queries. It serves from memory if the item is dirty/cached,
// otherwise falls back to the persistent store.
func (c *StamperStoreCache) Get(i storage.Item) error {
	k := key(i)
	if val, ok := c.cache.Load(k); ok {
		item := val.(storage.Item)
		// We marshal and unmarshal from the cloned item to ensure
		// safe copies and proper unmarshaler interface usage
		b, err := item.Marshal()
		if err != nil {
			return err
		}
		return i.Unmarshal(b)
	}
	return c.Store.Get(i)
}

// Has intercepts existence checks.
func (c *StamperStoreCache) Has(k storage.Key) (bool, error) {
	if _, ok := c.cache.Load(key(k)); ok {
		return true, nil
	}
	return c.Store.Has(k)
}

// Put intercepts writes. The cloned item is staged in RAM.
// It does NOT hit the disk.
func (c *StamperStoreCache) Put(i storage.Item) error {
	c.cache.Store(key(i), i.Clone())
	return nil
}

// Delete intercepts deletes, removing them from cache before falling
// straight through to the underlying persistent store.
func (c *StamperStoreCache) Delete(i storage.Item) error {
	c.cache.Delete(key(i))
	return c.Store.Delete(i)
}

// Close gracefully stops the flush loop and flushes all remaining items to disk.
func (c *StamperStoreCache) Close() error {
	close(c.quit)
	c.wg.Wait()
	return c.Store.Close()
}

// flushLoop runs passively, persisting memory to disk.
func (c *StamperStoreCache) flushLoop() {
	defer c.wg.Done()

	ticker := time.NewTicker(5 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-c.quit:
			c.flush()
			return
		case <-ticker.C:
			c.flush()
		}
	}
}

// flush commits the dirty cache map to the underlying store.
func (c *StamperStoreCache) flush() {
	// Try to get a batch if the underlying store supports it
	var batch storage.Batch
	if batcher, ok := c.Store.(storage.Batcher); ok {
		batch = batcher.Batch(context.Background())
	}

	// Delete from map and prepare to write
	c.cache.Range(func(k, v interface{}) bool {
		item := v.(storage.Item)
		c.cache.Delete(k) // removed from dirty cache

		var err error
		if batch != nil {
			err = batch.Put(item)
		} else {
			err = c.Store.Put(item)
		}

		if err != nil {
			// If flush fails, re-insert to try again next tick
			c.cache.Store(k, item)
		}
		return true
	})

	// Commit batch if it exists
	if batch != nil {
		_ = batch.Commit()
	}
}
